function updateSevenDaysCheck() {
  var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  var rangeToWatch = sheet.getRange('G2:G25');
  var values = rangeToWatch.getValues();
  var timestampColumn = rangeToWatch.getColumn() + 1;

