function updateTimestampIfMoreThan7Days() {
  var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  var rangeToCheck = sheet.getRange('A1:A25'); // Modify the range as needed
  var values = rangeToCheck.getValues();

  for (var i = 0; i < values.length; i++) {
    var cellValue = values[i][0];
    if (cellValue instanceof Date && isNaN(cellValue) === false) {
      var currentDate = new Date();
      var cellDate = new Date(cellValue);
      var differenceInDays = Math.floor((currentDate - cellDate) / (1000 * 60 * 60 * 24));

      if (differenceInDays > 7) {
        sheet.getRange(i + rangeToCheck.getRow(), rangeToCheck.getColumn() + 1).setValue(new Date());
      }
    }
  }
}
```

